module accu (
    input               clk,
    input               rst_n,
    input       [7:0]   data_in,
    input               valid_in,
    output  reg         valid_out,
    output  reg [9:0]   data_out
);

reg [9:0] accumulator;
reg [2:0] counter;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        accumulator <= 10'd0;
        counter <= 3'd0;
        valid_out <= 1'b0;
    end else if (valid_in == 1'b1 && counter < 3'd4) begin

        accumulator <= accumulator + {2'b00, data_in};
        counter <= counter + 1;
        valid_out <= 1'b0;
    end else if (counter == 3'd4) begin

        counter <= 3'd0;
        valid_out <= 1'b1;
    end else begin

        valid_out <= 1'b0;
    end
end

assign data_out = accumulator;

endmodule
